using namespace std;

bool solve(std::vector<long long> nums1) {
    int n = nums1.size();
    if (n == 1) return true;

    // Preprocessing: Separate and sort even and odd numbers
    std::vector<long long> evens;
    std::vector<long long> odds;
    for (long long x : nums1) {
        if (x % 2 == 0) {
            evens.push_back(x);
        } else {
            odds.push_back(x);
        }
    }
    std::sort(evens.begin(), evens.end());
    std::sort(odds.begin(), odds.end());

    // Helper function to check if a construction is possible targeting parity P (0 for Even, 1 for Odd)
    auto check_optimized = [&](int P) -> bool {
        for (int i = 0; i < n; ++i) {
            long long currentNum = nums1[i];
            bool possible = false;

            // Option 1: nums2[i] = nums1[i]
            if (currentNum % 2 == P) {
                possible = true;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j] >= 1, parity P
            if (!possible) {
                // Determine the required parity for nums1[j]
                int requiredParityJ;
                if (P == 0) { // Target Even: currentNum and nums1[j] must have same parity
                    requiredParityJ = currentNum % 2;
                } else { // Target Odd: currentNum and nums1[j] must have different parity
                    requiredParityJ = 1 - (currentNum % 2);
                }

                // Select the list containing candidates for nums1[j]
                const std::vector<long long>& candidates = (requiredParityJ == 0) ? evens : odds;

                // We need to find if there exists candidate < currentNum in this list.
                // Use binary search (std::lower_bound) to find the first element >= currentNum.
                auto it = std::lower_bound(candidates.begin(), candidates.end(), currentNum);

                // If it is not the beginning of the list, the element right before 'it' is the largest element < currentNum.
                // Since candidates are unique and sorted, if there's at least one element smaller, this check passes.
                if (it != candidates.begin()) {
                    // At least one element smaller than currentNum exists in candidates.
                    possible = true;
                }
            }

            if (!possible) {
                return false;
            }
        }
        return true;
    };

    // Check if ALL ODD is possible OR if ALL EVEN is possible
    return check_optimized(1) || check_optimized(0);
}

